// IInteractable.h — the contract
UINTERFACE(MinimalAPI)
class UInteractable : public UInterface
{
    GENERATED_BODY()
};

class IInteractable
{
    GENERATED_BODY()
public:
    UFUNCTION(BlueprintNativeEvent, BlueprintCallable)
    void Interact(AActor* Caller);

    UFUNCTION(BlueprintNativeEvent, BlueprintCallable)
    FText GetInteractionPrompt();

    UFUNCTION(BlueprintNativeEvent, BlueprintCallable)
    bool CanInteract(AActor* Caller);
};

// InteractionComponent.h — on the player, handles detection
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UInteractionComponent : public UActorComponent
{
    GENERATED_BODY()
public:
    UPROPERTY(EditAnywhere, Category = "Interaction")
    float InteractionRange = 300.f;

    UFUNCTION(BlueprintCallable)
    void TryInteract();

    UPROPERTY(BlueprintReadOnly)
    AActor* CurrentTarget;

    DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnTargetChanged, AActor*, NewTarget);

    UPROPERTY(BlueprintAssignable)
    FOnTargetChanged OnTargetChanged;

protected:
    virtual void TickComponent(float DeltaTime, ELevelTick TickType,
        FActorComponentTickFunction* ThisTickFunction) override;
    void PerformTrace();
};

// A door implementing the interface
class AMyDoor : public AActor, public IInteractable
{
    GENERATED_BODY()
public:
    virtual void Interact_Implementation(AActor* Caller) override
    {
        bIsOpen = !bIsOpen;
        // Play open/close animation
    }

    virtual FText GetInteractionPrompt_Implementation() override
    {
        return bIsOpen ? FText::FromString("Close Door") : FText::FromString("Open Door");
    }

    virtual bool CanInteract_Implementation(AActor* Caller) override
    {
        return !bIsLocked;
    }
};
